TriggerOraclev10g.body:
BEGIN
  IF INSERTING OR (UPDATING AND :NEW.ID_FAMILIA != :OLD.ID_FAMILIA) THEN
    UPDATE SIAC_FAMILIA
       SET CANTIDAD_MIEMBROS = (
             SELECT COUNT(*) FROM SIAC_PERSONA
              WHERE ID_FAMILIA = :NEW.ID_FAMILIA
                AND ESTADO     = 'ACTIVO'
           )
     WHERE ID_FAMILIA = :NEW.ID_FAMILIA;
  END IF;

  IF DELETING OR (UPDATING AND :NEW.ID_FAMILIA != :OLD.ID_FAMILIA) THEN
    UPDATE SIAC_FAMILIA
       SET CANTIDAD_MIEMBROS = (
             SELECT COUNT(*) FROM SIAC_PERSONA
              WHERE ID_FAMILIA = :OLD.ID_FAMILIA
                AND ESTADO     = 'ACTIVO'
           )
     WHERE ID_FAMILIA = :OLD.ID_FAMILIA;
  END IF;
END;
